(async () => {
  const delay = (ms) => new Promise(res => setTimeout(res, ms));

  try {
    // 0) Validar confirmación
    if (!Chk_entiendo?.isChecked) {
      showAlert("Debes marcar la casilla de confirmación para continuar.", "warning");
      return;
    }

    // Evitar doble envío
    if (
      UpdatePedidos.isLoading ||
      UpdateInventarioEditOld.isLoading ||
      UpdateInventarioEditNew.isLoading ||
      InsertOTOld.isLoading ||
      InsertOTNew.isLoading
    ) {
      return;
    }

    // Recalcular cambio en runtime — fuente de verdad final
    const idOriginal = appsmith.store.bano_original_pedido || null;
    const idNuevo = appsmith.store.bano_nuevo_obj?.id_bano || null;
    const cambioBano = idOriginal && idNuevo ? idNuevo !== idOriginal : false;

    const banoOriginalObj = appsmith.store.bano_original_obj || {};
    const banoNuevoObj = appsmith.store.bano_nuevo_obj || {};
    const pedido = appsmith.store.cliente_edit_row || {};

    // ── SIEMPRE: Actualizar pedido ──────────────────────────────────
    await UpdatePedidos.run();
    await delay(500);

    // ── SOLO si hubo cambio de baño ─────────────────────────────────
    if (cambioBano) {

      // 1) Actualizar inventario baño original → "Limpieza en almacen"
      await UpdateInventarioEditOld.run();
      await delay(500);

      // 2) Actualizar inventario baño nuevo → "Colocado con cliente"
      await UpdateInventarioEditNew.run();
      await delay(500);

      // 3) Calcular fecha programada (mañana)
      const hoy = new Date();
      const manana = new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate() + 1);
      const fechaProgramada = manana.toISOString().split('T')[0];
      await storeValue("fecha_programada_ot", fechaProgramada, true);

      // 4) OT recolección — baño original sale
      await InsertOTOld.run({
        id_bano: banoOriginalObj.id_bano || null,
        nombre_ubicacion: pedido.nombre_ubicacion || null,
        id_ruta: pedido.id_ruta || null,
        id_item_pedido: pedido.id_item_pedido || null,
        id_ubicacion: pedido.id_ubicacion || null,
        geolocalizacion_ubicacion: pedido.geolocalizacion_ubicacion || null,
        actividad_programada: "Recoleccion con cliente",
        estatus_ot: "Activa",
        fecha_programada: fechaProgramada
      });
      await delay(500);

      // 5) OT entrega — baño nuevo entra
      await InsertOTNew.run({
        id_bano: banoNuevoObj.id_bano || null,
        nombre_ubicacion: pedido.nombre_ubicacion || null,
        id_ruta: pedido.id_ruta || null,
        id_item_pedido: pedido.id_item_pedido || null,
        id_ubicacion: pedido.id_ubicacion || null,
        geolocalizacion_ubicacion: pedido.geolocalizacion_ubicacion || null,
        actividad_programada: "Entrega con cliente",
        estatus_ot: "Activa",
        fecha_programada: fechaProgramada
      });
      await delay(500);

      showAlert("Pedido y cambio de baño actualizados correctamente.", "success");
    } else {
      showAlert("Pedido actualizado correctamente.", "success");
    }

    // ✅ Limpiar store y cerrar modales
    storeValue("pedido_edit_temp", null, false);
    storeValue("cambio_bano", false, true);
    storeValue("bano_nuevo_obj", null, true);
    storeValue("mensaje_cambio_bano", "No hay cambio de baño.", true);

    resetWidget("Modal_Procesar", true);
    resetWidget("Modal_confirmar_editar", true);

    if (GetPedidos?.run) { await GetPedidos.run(); }

    closeModal("Modal_confirmar_editar");
    closeModal("Modal_Editar");

  } catch (e) {
    showAlert("Error al guardar: " + (e?.message ?? e), "error");
    // ⚠️ No reseteamos en error para que el usuario pueda reintentar
  }
})()
}}
